-- Table structure for relic_image_relation_backup_20260428
-- ----------------------------
DROP TABLE IF EXISTS `relic_image_relation_backup_20260428`;
CREATE TABLE `relic_image_relation_backup_20260428` (
  `id` bigint NOT NULL DEFAULT '0' COMMENT '关联ID',
  `relic_id` bigint NOT NULL COMMENT '文物ID（唯一，确保一个文物只有一张主图）',
  `image_id` bigint NOT NULL COMMENT '图片ID（唯一，确保一张图片只关联一个文物）',
  `relation_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT 'main' COMMENT '关联类型（main:主图, detail:详情图等）',
  `sort_order` int DEFAULT '0' COMMENT '排序顺序',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间'
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

