-- ----------------------------
-- Table structure for sys_backup
-- ----------------------------
DROP TABLE IF EXISTS `sys_backup`;
CREATE TABLE `sys_backup` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '备份ID',
  `backup_name` varchar(200) NOT NULL COMMENT '备份名称',
  `backup_type` varchar(20) NOT NULL COMMENT '备份类型：manual-手动, auto-自动',
  `backup_status` varchar(20) NOT NULL DEFAULT 'processing' COMMENT '备份状态：processing-处理中, success-成功, failed-失败',
  `file_name` varchar(255) NOT NULL COMMENT '备份文件名',
  `file_path` varchar(500) NOT NULL COMMENT '备份文件路径',
  `file_size` bigint DEFAULT '0' COMMENT '文件大小（字节）',
  `is_encrypted` tinyint(1) DEFAULT '0' COMMENT '是否加密：0-否, 1-是',
  `backup_tables` text COMMENT '备份的表列表（JSON数组）',
  `description` varchar(500) DEFAULT NULL COMMENT '备份描述',
  `error_message` text COMMENT '错误信息',
  `created_by` varchar(50) DEFAULT NULL COMMENT '创建人',
  `created_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `deleted` tinyint(1) DEFAULT '0' COMMENT '是否删除：0-否, 1-是',
  PRIMARY KEY (`id`),
  KEY `idx_backup_type` (`backup_type`),
  KEY `idx_backup_status` (`backup_status`),
  KEY `idx_created_time` (`created_time`)
) ENGINE=InnoDB AUTO_INCREMENT=25 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='系统备份记录表';

-- ----------------------------
-- Records of sys_backup
-- ----------------------------

-- ----------------------------
-- Table structure for sys_backup_config
-- ----------------------------
DROP TABLE IF EXISTS `sys_backup_config`;
CREATE TABLE `sys_backup_config` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '配置ID',
  `config_name` varchar(100) NOT NULL COMMENT '配置名称',
  `is_enabled` tinyint(1) DEFAULT '1' COMMENT '是否启用：0-否, 1-是',
  `backup_frequency` varchar(20) NOT NULL COMMENT '备份频率：daily-每天, weekly-每周, monthly-每月',
  `backup_time` varchar(10) NOT NULL COMMENT '备份时间（HH:mm）',
  `retention_days` int DEFAULT '30' COMMENT '保留天数',
  `max_backup_count` int DEFAULT '10' COMMENT '最大备份数量',
  `is_encrypted` tinyint(1) DEFAULT '0' COMMENT '是否加密：0-否, 1-是',
  `backup_tables` text COMMENT '备份的表列表（JSON数组，为空则备份全部）',
  `notification_enabled` tinyint(1) DEFAULT '1' COMMENT '是否启用通知：0-否, 1-是',
  `created_by` varchar(50) DEFAULT NULL COMMENT '创建人',
  `created_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_by` varchar(50) DEFAULT NULL COMMENT '更新人',
  `updated_time` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='备份配置表';

-- ----------------------------
-- Records of sys_backup_config
-- ----------------------------

-- ----------------------------
-- Table structure for sys_data_change_detail
-- ----------------------------
DROP TABLE IF EXISTS `sys_data_change_detail`;
CREATE TABLE `sys_data_change_detail` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `log_id` bigint NOT NULL COMMENT '操作日志ID',
  `field_name` varchar(100) COLLATE utf8mb4_general_ci NOT NULL COMMENT '字段名称',
  `field_label` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '字段标签（中文名）',
  `old_value` text COLLATE utf8mb4_general_ci COMMENT '旧值',
  `new_value` text COLLATE utf8mb4_general_ci COMMENT '新值',
  `value_type` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '值类型：STRING, NUMBER, DATE, BOOLEAN, JSON',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`),
  KEY `idx_log_id` (`log_id`),
  CONSTRAINT `sys_data_change_detail_ibfk_1` FOREIGN KEY (`log_id`) REFERENCES `sys_operation_log` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=9 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='数据变更详情表';

