-- ----------------------------
-- Table structure for sys_operation_log
-- ----------------------------
DROP TABLE IF EXISTS `sys_operation_log`;
CREATE TABLE `sys_operation_log` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `operator` varchar(50) COLLATE utf8mb4_general_ci NOT NULL,
  `operation_type` varchar(50) COLLATE utf8mb4_general_ci NOT NULL,
  `operation_module` varchar(50) COLLATE utf8mb4_general_ci NOT NULL,
  `operation_content` varchar(1000) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `operation_result` varchar(20) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `ip_address` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `operation_time` datetime DEFAULT CURRENT_TIMESTAMP,
  `user_id` bigint DEFAULT NULL COMMENT '操作用户ID',
  `resource_type` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '资源类型：RELIC-文物，LOAN-借展，REPAIR-修复等',
  `resource_id` bigint DEFAULT NULL COMMENT '资源ID',
  `before_data` text COLLATE utf8mb4_general_ci COMMENT '操作前数据（JSON格式）',
  `after_data` text COLLATE utf8mb4_general_ci COMMENT '操作后数据（JSON格式）',
  `changed_fields` text COLLATE utf8mb4_general_ci COMMENT '变更字段列表（JSON格式）',
  `request_method` varchar(10) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '请求方法：GET, POST, PUT, DELETE',
  `request_url` varchar(500) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '请求URL',
  `request_params` text COLLATE utf8mb4_general_ci COMMENT '请求参数（JSON格式）',
  `response_data` text COLLATE utf8mb4_general_ci COMMENT '响应数据（JSON格式）',
  `error_message` text COLLATE utf8mb4_general_ci COMMENT '错误信息',
  `execution_time` bigint DEFAULT NULL COMMENT '执行时长（毫秒）',
  `user_agent` varchar(500) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '用户代理',
  `browser` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '浏览器',
  `os` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '操作系统',
  PRIMARY KEY (`id`),
  KEY `idx_operator` (`operator`),
  KEY `idx_operation_time` (`operation_time`),
  KEY `idx_user_id` (`user_id`),
  KEY `idx_resource` (`resource_type`,`resource_id`),
  KEY `idx_operation_type` (`operation_type`),
  KEY `idx_operation_result` (`operation_result`)
) ENGINE=InnoDB AUTO_INCREMENT=1091 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- ----------------------------
-- Records of sys_operation_log
-- ----------------------------


