  KEY `idx_restore_status` (`restore_status`),
  CONSTRAINT `sys_restore_ibfk_1` FOREIGN KEY (`backup_id`) REFERENCES `sys_backup` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=5 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='系统恢复记录表';

