-- ----------------------------
-- Table structure for system_notification
-- ----------------------------
DROP TABLE IF EXISTS `system_notification`;
CREATE TABLE `system_notification` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '通知ID',
  `title` varchar(200) NOT NULL COMMENT '通知标题',
  `content` text NOT NULL COMMENT '通知内容',
  `type` varchar(50) NOT NULL COMMENT '通知类型：LOAN_APPLY(借展申请)、LOAN_OVERDUE(借展逾期)、REPAIR_APPLY(修复申请)、LOAN_APPROVED(借展审批通过)、LOAN_REJECTED(借展审批拒绝)、REPAIR_APPROVED(修复审批通过)、REPAIR_REJECTED(修复审批拒绝)',
  `priority` varchar(20) NOT NULL DEFAULT 'NORMAL' COMMENT '优先级：LOW(低)、NORMAL(普通)、HIGH(高)、URGENT(紧急)',
  `related_type` varchar(50) DEFAULT NULL COMMENT '关联类型：LOAN(借展)、REPAIR(修复)',
  `related_id` bigint DEFAULT NULL COMMENT '关联ID（借展记录ID或修复记录ID）',
  `sender_id` bigint DEFAULT NULL COMMENT '发送人ID',
  `sender_name` varchar(100) DEFAULT NULL COMMENT '发送人姓名',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`),
  KEY `idx_type` (`type`),
  KEY `idx_related` (`related_type`,`related_id`),
  KEY `idx_create_time` (`create_time`)
) ENGINE=InnoDB AUTO_INCREMENT=31 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='系统通知表';

